function regionNames(sample){const all=COUNTRY_REGIONS[sample.country]||FALLBACK;return all.slice(0,Math.min(8,Math.max(5,all.length)));}
function sectorMetrics(sample){return SECTOR_METRICS[sample.sector]||SECTOR_METRICS.Governance;}
function makeRegional(sample,r){const names=regionNames(sample),total=4800+Math.floor(r()*5200),weights=names.map(()=>.75+r()*.7),sum=weights.reduce((a,b)=>a+b,0);let used=0;return names.map((name,i)=>{const n=i===names.length-1?total-used:Math.round(total*weights[i]/sum);used+=n;const score=pct(48+r()*38);return{name,responses:n,primary_score:score,satisfaction:pct(clamp(score-4+r()*12,35,94)),women_pct:pct(48+r()*8),youth_pct:pct(30+r()*28),disability_pct:pct(4+r()*10),rural_pct:pct(28+r()*54),risk:score<58?'High':score<70?'Medium':'Low'};});}
