function makeRawRows(sample,regional,demographics,r){const rows=[];for(let i=0;i<240;i++){const reg=regional[i%regional.length],sex=demographics.sex[i%demographics.sex.length][0],age=demographics.age[i%demographics.age.length][0];rows.push({response_id:`SYN-${sample.key}-${String(i+1).padStart(4,'0')}`,region:reg.name,sex,age_group:age,disability:i%11===0?'Yes':'No',channel:['Voice','WhatsApp','SMS','Web','Offline App'][i%5],score:Math.round(clamp(reg.primary_score+(r()-.5)*22,10,100)),consent:'Yes',quality_status:i%29===0?'Reviewed':'Passed'});}return rows;}
