const arr=v=>Array.isArray(v)?v:[]; const txt=v=>String(v??'').trim();
const PACKS={compliance:['data_protection','ethics','safeguarding','regulatory_mapping','audit_register'],security:['architecture','access_control','encryption','incident_response','business_continuity','penetration_test'],methodology:['research_design','sampling','analysis_plan','quality_assurance','limitations'],evidence:['evidence_register','citation_index','traceability_map','approval_records'],technical_architecture:['system_context','data_flow','integrations','deployment','resilience'],operational_manual:['support_model','monitoring','incident_management','backup_restore','change_management'],administrator_guide:['user_management','roles','projects','data_governance','reports','operations']};
export function generateProcurementPack(input={}){
 const packs={}; for(const [name,required] of Object.entries(PACKS)){const source=input[name]||{}; const items=required.map(k=>({item:k,status:source[k]?'AVAILABLE':'MISSING',document_reference:txt(source[k]?.document_reference||source[k])})); const score=Math.round(items.filter(i=>i.status==='AVAILABLE').length/items.length*100); packs[name]={name,items,score,status:score===100?'READY':score>=70?'PARTIAL':'NOT_READY'};}
 const score=Math.round(Object.values(packs).reduce((s,p)=>s+p.score,0)/Object.keys(packs).length); const blockers=Object.values(packs).filter(p=>p.status!=='READY').map(p=>p.name);
 return {procurement_pack_version:'v216.0',generated_at:new Date().toISOString(),organization_id:txt(input.organization_id),packs,score,status:blockers.length?'NOT_READY':'READY',blockers,external_requirements:['Independent penetration test','Legal opinion where required','Client-specific due diligence','Live SLA and disaster-recovery exercise evidence']};
}
export {PACKS};
